import axios from 'axios';

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:8080",
});

// Añadimos un interceptor para inyectar el token JWT en cada petición automáticamente
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers['Authorization'] = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Añadimos un interceptor para detectar si el token expira o es inválido (error 401/403)
api.interceptors.response.use(
  (response) => response,
  (error) => {
    // Si el error 401 viene de la ruta de login, no recargamos la página. 
    // Dejamos que el componente LoginPage muestre el mensaje de "Contraseña incorrecta".
    if (error.config && error.config.url.includes('/auth/login')) {
      return Promise.reject(error);
    }

    if (error.response && (error.response.status === 401 || error.response.status === 403)) {
      // Si el backend nos rechaza el token en cualquier otra ruta, cerramos sesión de inmediato
      localStorage.removeItem('token');
      localStorage.removeItem('loggedUser');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

export default api;
